import{_ as a,c as r,o,a2 as t}from"./chunks/framework.CIiVzG-O.js";const f=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1784003192000}'),p={name:"guide/faq.md"};function i(s,e,n,l,u,d){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Q: What is NueZip?</p><p>A: NueZip is a professional archive manager for macOS, supporting compression and extraction of multiple archive formats including RAR, ZIP, 7-Zip, TAR, GZIP, and BZIP2.</p><p>Q: Which macOS versions are supported?</p><p>A: NueZip requires macOS 14 Sonoma or later, and is optimized for Apple Silicon (M-series) chips.</p><p>Q: How do I download and install NueZip?</p><p>A: Download from the <a href="https://apps.apple.com/app/id6785846417" target="_blank" rel="noreferrer">Mac App Store</a> (recommended) or grab the latest release from <a href="https://github.com/nuezip/nuezip/releases" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><p>Q: Is NueZip free?</p><p>A: NueZip offers a free trial with core features. A one-time purchase unlocks the full feature set including batch operations, archive repair, and advanced encryption.</p><p>Q: What formats are supported?</p><p>A: <strong>Read</strong>: RAR, ZIP, 7-Zip, TAR, GZIP, BZIP2, XZ, Zstandard<br><strong>Write (compress)</strong>: ZIP, 7-Zip, TAR, GZIP, BZIP2, XZ, Zstandard<br> See <a href="/guide/introduction.html">Introduction</a> for the full format matrix.</p><p>Q: Can NueZip create RAR archives?</p><p>A: No. NueZip can <strong>read</strong> RAR archives (including multi-volume and repaired archives), but RAR compression is not supported due to licensing restrictions.</p><p>Q: Is NueZip safe for confidential files?</p><p>A: Yes. NueZip operates entirely offline. All operations run locally on your Mac. AES-256 encryption is available for password-protected ZIP archives.</p><p>Q: Does NueZip upload my files to the cloud?</p><p>A: No. NueZip is a fully offline application. Your files are never uploaded anywhere. No internet connection is required for compression or extraction.</p><p>Q: How do I update the app?</p><p>A: Update through the Mac App Store (automatic) or download the latest release from GitHub Releases.</p><p>Q: How do I report bugs or request features?</p><p>A: Open an issue on the <a href="https://github.com/nuezip/nuezip/issues" target="_blank" rel="noreferrer">GitHub repository</a>. Please include your macOS version, NueZip version, and steps to reproduce.</p><p>Q: Where are logs and data stored?</p><p>A: For sandboxed (App Store) builds:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Containers/com.w3cub.nuezip/Data/Library/Application Support/com.w3cub.nuezip/</span></span></code></pre></div><p>Development builds may log to the console or <code>src-tauri</code> directory.</p><p>If you need more answers, please open an issue in the repository or consult the full documentation.</p>',26)])])}const h=a(p,[["render",i]]);export{f as __pageData,h as default};
